mapper.select:
SELECT A.rqst_no, A.title, A.rqst_id, A.ins_dt, A.upt_dt, A.views, A.group_no, A.parent_no, A.depth, A.order_no, A.secret, (SELECT COUNT(*) FROM comment WHERE board_no = A.rqst_no) AS commentCount FROM board A WHERE A.board_type = 'NOTICE'
AND A.title LIKE CONCAT('%', #{keyword}, '%') AND A.cont LIKE CONCAT('%', #{keyword}, '%') AND A.rqst_id LIKE CONCAT('%', #{keyword}, '%') AND (A.title LIKE CONCAT('%', #{keyword}, '%') OR A.cont LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY A.group_no DESC, A.order_no ASC, A.ins_dt DESC LIMIT #{size} OFFSET #{offset}
